// Counter sederhana
function Counter() {
  const [hitung, setHitung] = useState(0); // nilai awal = 0

  return (
    <div className="counter">
      <button onClick={() => setHitung(h => h - 1)}>−</button>
      <span className="nilai">{hitung}</span>
      <button onClick={() => setHitung(h => h + 1)}>+</button>
      <button onClick={() => setHitung(0)}>Reset</button>
    </div>
  );
}

