// Render list dengan map() + conditional
function DaftarMahasiswa() {
  const [filter, setFilter] = useState('semua');
  const [isLoading, setIsLoading] = useState(false);

  // Filter data berdasarkan state
  const dataFiltered = dataMahasiswa.filter(mhs => {
    if (filter === 'aktif') return mhs.aktif;
    if (filter === 'nonaktif') return !mhs.aktif;
    return true;
  });

  // Conditional rendering: loading state
  if (isLoading) {
    return <div className="loading-spinner">Memuat data...</div>;
  }

  return (
    <div>
      {/* Filter buttons */}
      <div className="filter-group">
        {['semua', 'aktif', 'nonaktif'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            className={filter === f ? 'aktif' : ''}
          >
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {/* Conditional: data kosong */}
      {dataFiltered.length === 0 ? (
        <p className="empty-state">Tidak ada mahasiswa dengan filter ini.</p>
      ) : (
        <ul className="daftar-mahasiswa">
          {dataFiltered.map(mhs => (
            <li key={mhs.id} className="item-mahasiswa">  {/* key WAJIB! */}
              <strong>{mhs.nama}</strong>
              <span>IPK: {mhs.ipk}</span>

              {/* Logical && untuk badge opsional */}
              {mhs.ipk >= 3.5 && (
                <span className="badge-cumlaude">🏆 Cumlaude</span>
              )}

              {/* Ternary untuk status */}
              <span className={`status ${mhs.aktif ? 'aktif' : 'nonaktif'}`}>
                {mhs.aktif ? '✅ Aktif' : '❌ Nonaktif'}
              </span>
            </li>
          ))}
        </ul>
      )}

      <p>Menampilkan {dataFiltered.length} dari {dataMahasiswa.length} mahasiswa</p>
    </div>
  );
}

import { useState, useEffect } from 'react';

// Fetch data saat component pertama kali dimuat
function DaftarPost() {
  const [posts, setPosts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Effect: jalankan fetch saat pertama kali mount
    async function ambilPosts() {
      try {
        const res = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=5');
        if (!res.ok) throw new Error('Gagal mengambil data');
        const data = await res.json();
        setPosts(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setIsLoading(false);
      }
    }
    ambilPosts();
  }, []); // [] = jalankan sekali saat mount

  if (isLoading) return <p>Memuat...</p>;
  if (error) return <p>Error: {error}</p>;
  return <ul>{posts.map(p => <li key={p.id}>{p.title}</li>)}</ul>;
}

