// Cleanup: sangat penting untuk mencegah memory leak
function Jam() {
  const [waktu, setWaktu] = useState(new Date());

  useEffect(() => {
    // Setup: mulai interval
    const interval = setInterval(() => {
      setWaktu(new Date());
    }, 1000);

    // Cleanup function: dijalankan sebelum effect berikutnya atau saat unmount
    return () => {
      clearInterval(interval); // WAJIB! Tanpa ini, interval terus jalan meski component hilang
    };
  }, []); // Hanya sekali

  return <p>Waktu: {waktu.toLocaleTimeString('id-ID')}</p>;
}

