import { useState } from 'react';

function FormDaftar() {
  // State untuk nilai form
  const [form, setForm] = useState({
    nama: '', email: '', password: '', jurusan: '', setuju: false
  });

  // State untuk error validasi per field
  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [sukses, setSukses] = useState(false);

  // Handler perubahan field
  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    // Hapus error field ini saat user mulai mengetik
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  // Fungsi validasi
  const validasi = () => {
    const err = {};
    if (!form.nama.trim()) err.nama = 'Nama wajib diisi';
    else if (form.nama.trim().length < 3) err.nama = 'Nama minimal 3 karakter';

    if (!form.email) err.email = 'Email wajib diisi';
    else if (!/\S+@\S+\.\S+/.test(form.email)) err.email = 'Format email tidak valid';

    if (!form.password) err.password = 'Password wajib diisi';
    else if (form.password.length < 8) err.password = 'Password minimal 8 karakter';

    if (!form.jurusan) err.jurusan = 'Pilih jurusan terlebih dahulu';

    if (!form.setuju) err.setuju = 'Anda harus menyetujui syarat dan ketentuan';

    return err;
  };

  // Handler submit
  const handleSubmit = async (e) => {
    e.preventDefault(); // WAJIB!
    const err = validasi();
    if (Object.keys(err).length > 0) {
      setErrors(err);
      return;
    }
    setIsSubmitting(true);
    try {
      await daftarkan(form); // API call
      setSukses(true);
      setForm({ nama: '', email: '', password: '', jurusan: '', setuju: false });
    } catch (err) {
      setErrors({ submit: err.message });
    } finally {
      setIsSubmitting(false);
    }
  };

  if (sukses) return <div className="sukses">✅ Pendaftaran berhasil!</div>;

  return (
    <form onSubmit={handleSubmit} className="form-daftar" noValidate>
      <h2>Formulir Pendaftaran</h2>
      {errors.submit && <div className="alert error">{errors.submit}</div>}

      <div className="field">
        <label htmlFor="nama">Nama Lengkap</label>
        <input id="nama" name="nama" type="text"
          value={form.nama} onChange={handleChange}
          className={errors.nama ? 'input-error' : ''}
        />
        {errors.nama && <span className="pesan-error">{errors.nama}</span>}
      </div>

      <div className="field">
        <label htmlFor="jurusan">Jurusan</label>
        <select id="jurusan" name="jurusan"
          value={form.jurusan} onChange={handleChange}
        >
          <option value="">-- Pilih Jurusan --</option>
          <option value="ti">Teknik Informatika</option>
          <option value="si">Sistem Informasi</option>
        </select>
        {errors.jurusan && <span className="pesan-error">{errors.jurusan}</span>}
      </div>

      <button type="submit" disabled={isSubmitting}>
        {isSubmitting ? 'Mendaftar...' : 'Daftar Sekarang'}
      </button>
    </form>
  );
}

