import { createContext, useContext, useState, useEffect } from 'react';

// =============================================
// 1. Buat Context
// =============================================
const AuthContext = createContext(null);
const TemaContext = createContext(null);

// =============================================
// 2. Buat Provider Component
// =============================================
function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  // Cek session saat pertama load
  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) setUser(JSON.parse(userData));
    setIsLoading(false);
  }, []);

  const login = async (email, password) => {
    const userData = await apiLogin(email, password);
    setUser(userData);
    localStorage.setItem('user', JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  // Value yang dibagikan ke semua consumer
  const value = { user, isLoading, login, logout };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}

function TemaProvider({ children }) {
  const [tema, setTema] = useState(() => {
    return localStorage.getItem('tema') ?? 'terang';
  });

  const toggleTema = () => {
    setTema(prev => {
      const baru = prev === 'terang' ? 'gelap' : 'terang';
      localStorage.setItem('tema', baru);
      return baru;
    });
  };

  return (
    <TemaContext.Provider value={{ tema, toggleTema }}>
      <div data-tema={tema}>{children}</div>
    </TemaContext.Provider>
  );
}

// Custom hook untuk akses yang lebih bersih
function useAuth() {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth harus digunakan di dalam AuthProvider');
  return context;
}

function useTema() {
  return useContext(TemaContext);
}

// =============================================
// 3. Wrap App dengan Provider
// =============================================
function main() {
  return (
    <TemaProvider>
      <AuthProvider>
        <App />
      </AuthProvider>
    </TemaProvider>
  );
}

// =============================================
// 4. Gunakan context di component manapun
// =============================================
function Navbar() {
  const { user, logout } = useAuth();   // akses context langsung!
  const { tema, toggleTema } = useTema();

  return (
    <nav>
      <span>Halo, {user?.nama ?? 'Tamu'}!</span>
      <button onClick={toggleTema}>
        {tema === 'terang' ? '🌙' : '☀️'}
      </button>
      {user && <button onClick={logout}>Logout</button>}
    </nav>
  );
}

